import { z } from 'zod';
import type {
  ClassificationResult,
  ClassificationSession,
  EmailMessage,
  RulePattern,
  StrongIndicatorResult,
} from '../types';
import {
  extractDomainFromEmail,
  findMatchingDomain,
  findMatchingKeywords,
  extractEmailBodyText,
} from '../utils/email-utils';
import { ConfidenceThresholds, ConfidenceThresholdsSchema } from './types';
import { matchRulePattern } from '../utils/rule-matcher';
import { RulePatternSchema } from '../config/category-config-schema';

/**
 * Strong Indicators Stage
 *
 * Implements diminishing returns seeding per SCORING_LOGIC.md "Strong Indicator Seeding" section.
 * High-weight signals that provide strong category hints, applied with diminishing returns
 * across multiple dimensions (subject, fromDomain, body).
 *
 * CANONICAL SIGNATURE: (email, session, result, config) => void
 *
 * Logic:
 * - seed = Σ weightedMatches
 * - Diminishing returns per dimension: first full, rest * 0.5
 * - strongIndicatorSeed = max(existingSeed, seed)
 * - Applied after hard assertions before subtype accumulation
 * - Mutates result.explainabilityTrace and result.scoreBreakdown instead of returning
 */

export interface StrongIndicatorConfig {
  fromDomainsRef?: {
    sourceGroup: string;
    confidence: 'high' | 'medium' | 'low';
  };
  subjectContains?: string[];
  bodyContains?: string[];
  customRules?: RulePattern[];
  diminishingReturns?: {
    enabled?: boolean;
    decayFactor?: number;
    maxIndicators?: number;
  };
}

export interface StrongIndicatorStageConfig {
  confidenceThresholds: ConfidenceThresholds;
  categorySignals: Record<string, { strongIndicators?: StrongIndicatorConfig }>;
  domainLookup: Record<
    string,
    {
      highConfidence: Array<{ domain: string; type?: string }>;
      mediumConfidence: Array<{ domain: string; type?: string }>;
      lowConfidence: Array<{ domain: string; type?: string }>;
    }
  >;
  // Weight for strong indicators (typically 8-12 range for medium-high confidence)
  strongIndicatorBaseWeight: number;
  // Diminishing returns factor for subsequent matches in same dimension
  diminishingReturnsFactor: number;
}

/**
 * Executes strong indicators stage of email classification
 *
 * CANONICAL SIGNATURE: Mutates result object instead of returning values
 *
 * @param email - Email message to analyze for strong indicator matches
 * @param session - Classification session batch metadata (canonical signature parameter, not used directly)
 * @param result - Classification result to update (mutated in place)
 * @param config - Strong indicator configuration with domain lookups and patterns
 */
export function executeStrongIndicators(
  email: EmailMessage,
  _session: ClassificationSession,
  result: ClassificationResult,
  config: StrongIndicatorStageConfig
): void {
  const startTime = Date.now();

  const categoriesWithStrongIndicators: string[] = [];
  const indicatorResults: StrongIndicatorResult[] = [];

  const baseWeight = config.strongIndicatorBaseWeight;
  const defaultDecay = config.diminishingReturnsFactor;

  // Process each category that has strong indicators configured
  for (const [categoryName, categoryConfig] of Object.entries(config.categorySignals)) {
    if (!categoryConfig.strongIndicators) {
      continue;
    }

    const strongIndicators = categoryConfig.strongIndicators;
    // Read existing seed from result.scoreBreakdown
    const existingSeed = result.scoreBreakdown.categoryScores[categoryName]?.strongIndicatorScore || 0;
    let categoryHadIndicator = false;
    let newSeedScore = existingSeed;

    // Track matches per dimension for diminishing returns
    const dimensionMatches = {
      fromDomain: 0,
      subjectContains: 0,
      bodyContains: 0,
      customRule: 0,
    };
    let totalIndicators = 0;

    const diminishingOverrides = strongIndicators.diminishingReturns ?? {};
    const applyDiminishing = diminishingOverrides.enabled ?? true;
    const decayFactor = diminishingOverrides.decayFactor ?? defaultDecay;
    const maxIndicators = diminishingOverrides.maxIndicators ?? Infinity;

    const registerIndicator = (
      dimension: keyof typeof dimensionMatches,
      matchedValue: string,
      baseReason: string,
      weightMultiplier = 1
    ) => {
      if (totalIndicators >= maxIndicators) {
        return false;
      }

      const normalizedWeight = weightMultiplier > 0 ? weightMultiplier : 0;
      if (normalizedWeight === 0) {
        return false;
      }

      dimensionMatches[dimension] += 1;

      const isFirstMatch = dimensionMatches[dimension] === 1;
      const shouldApplyDecay = applyDiminishing && !isFirstMatch;
      const effectiveBase = baseWeight * normalizedWeight;
      const effectiveWeight = shouldApplyDecay ? effectiveBase * decayFactor : effectiveBase;
      const proposedSeed = newSeedScore + effectiveWeight;
      const indicatorType = dimension as StrongIndicatorResult['indicatorType'];

      indicatorResults.push({
        category: categoryName,
        indicatorType,
        matchedValue,
        seedScore: effectiveWeight,
        diminishingReturnsApplied: shouldApplyDecay,
        existingSeedScore: newSeedScore,
        finalSeedScore: proposedSeed,
        reason: `${baseReason} Weight: ${effectiveWeight.toFixed(2)}${shouldApplyDecay ? ' (diminished)' : ''}`,
      });

      newSeedScore = Math.max(newSeedScore, proposedSeed);
      totalIndicators += 1;
      categoryHadIndicator = true;
      return true;
    };

    // Check fromDomainsRef (domain-based strong indicators)
    if (strongIndicators.fromDomainsRef && totalIndicators < maxIndicators) {
      const { sourceGroup, confidence } = strongIndicators.fromDomainsRef;

      const domainGroup = config.domainLookup[sourceGroup];
      if (domainGroup) {
        const emailDomain = extractDomainFromEmail(email.from.email);
        const matchedDomain = findMatchingDomain(emailDomain, domainGroup, confidence);

        if (matchedDomain) {
          if (
            !registerIndicator(
              'fromDomain',
              matchedDomain.domain,
              `Email from domain '${emailDomain}' matches ${confidence}-confidence domain '${matchedDomain.domain}' in group '${sourceGroup}'.`
            )
          ) {
            totalIndicators = maxIndicators;
          }
        }
      }
    }

    // Check subjectContains
    if (strongIndicators.subjectContains && email.subject && totalIndicators < maxIndicators) {
      const matchedKeywords = findMatchingKeywords(email.subject, strongIndicators.subjectContains);

      for (const keyword of matchedKeywords) {
        if (
          !registerIndicator(
            'subjectContains',
            keyword,
            `Subject '${email.subject}' contains strong indicator keyword '${keyword}'.`
          )
        ) {
          break;
        }
      }
    }

    // Check bodyContains
    if (strongIndicators.bodyContains && totalIndicators < maxIndicators) {
      const bodyText = extractEmailBodyText(email);
      const matchedKeywords = findMatchingKeywords(bodyText, strongIndicators.bodyContains);

      for (const keyword of matchedKeywords) {
        if (!registerIndicator('bodyContains', keyword, `Body text contains strong indicator keyword '${keyword}'.`)) {
          break;
        }
      }
    }

    if (strongIndicators.customRules) {
      for (const rule of strongIndicators.customRules) {
        if (totalIndicators >= maxIndicators) {
          break;
        }

        const match = matchRulePattern(email, rule);
        if (match.matched) {
          const weightMultiplier = typeof rule.weight === 'number' ? rule.weight : 1;
          registerIndicator(
            'customRule',
            match.matchedValue,
            `Custom strong indicator rule (${rule.operation}) matched '${match.matchedValue}' on field '${rule.field}'.`,
            weightMultiplier
          );
        }
      }
    }

    // Update seed score using max logic (strongIndicatorSeed = max(existingSeed, seed))
    if (categoryHadIndicator) {
      // Update result.scoreBreakdown (mutate in place)
      if (!result.scoreBreakdown.categoryScores[categoryName]) {
        result.scoreBreakdown.categoryScores[categoryName] = {
          baseScore: 0,
          hardAssertionBonus: 0,
          strongIndicatorScore: 0,
          ruleScore: 0,
          attributeInfluenceScore: 0,
          finalScore: 0,
          parallelComputedComponents: [],
          computationDurationMs: 0,
          cacheHits: [],
          scoreAggregationSteps: [],
          cappingApplied: false,
        };
      }

      result.scoreBreakdown.categoryScores[categoryName].strongIndicatorScore = newSeedScore;
      result.scoreBreakdown.categoryScores[categoryName].finalScore = Math.max(
        result.scoreBreakdown.categoryScores[categoryName].finalScore,
        newSeedScore
      );
      categoriesWithStrongIndicators.push(categoryName);
    }
  }

  // Update result.explainabilityTrace with strong indicators (mutate in place)
  result.explainabilityTrace.strongIndicators = indicatorResults;

  // Track stage timing
  const durationMs = Date.now() - startTime;

  // Store timing in explainability trace
  result.explainabilityTrace.stageTimings['strongIndicators'] = durationMs;
  result.explainabilityTrace.configurationRefs['strongIndicators'] = 'categorySignals.*.strongIndicators';

  // Update processing duration
  result.processingDurationMs += durationMs;
}

/**
 * Zod schema for validating strong indicator configuration
 */
export const StrongIndicatorConfigSchema = z
  .object({
    fromDomainsRef: z
      .object({
        sourceGroup: z.string(),
        confidence: z.enum(['high', 'medium', 'low']),
      })
      .optional(),
    subjectContains: z.array(z.string()).optional(),
    bodyContains: z.array(z.string()).optional(),
    customRules: z.array(RulePatternSchema).optional(),
    diminishingReturns: z
      .object({
        enabled: z.boolean().optional(),
        decayFactor: z.number().min(0).max(1).optional(),
        maxIndicators: z.number().int().min(1).optional(),
      })
      .optional(),
  })
  .refine(
    (config) => {
      // At least one indicator type must be configured
      return !!(config.fromDomainsRef || config.subjectContains || config.bodyContains || config.customRules);
    },
    {
      message: 'At least one strong indicator type must be configured',
    }
  );

export const StrongIndicatorStageConfigSchema = z.object({
  confidenceThresholds: ConfidenceThresholdsSchema,
  categorySignals: z.record(
    z.object({
      strongIndicators: StrongIndicatorConfigSchema.optional(),
    })
  ),
  domainLookup: z.record(
    z.object({
      highConfidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
      mediumConfidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
      lowConfidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
    })
  ),
  strongIndicatorBaseWeight: z.number().min(0).default(10), // Typical range 8-12
  diminishingReturnsFactor: z.number().min(0).max(1).default(0.5), // First full, rest * 0.5
});

